export const normalizeTeamInput = (value) =>
  value
    ? value
        .normalize("NFD")
        .replace(/\p{Diacritic}/gu, "")
        .toLowerCase()
        .replace(/[^a-z0-9]+/g, " ")
        .trim()
    : "";

export const resolveCanonicalTeam = (input) => {
  const key = normalizeTeamInput(input || "");
  return TEAM_ALIASES[key] || (input ? input.trim() : "");
};

const CANONICAL_TO_SPANISH = TEAM_OPTIONS_ES.reduce((acc, name) => {
  const canonical = resolveCanonicalTeam(name);
  if (canonical && !acc[canonical]) {
    acc[canonical] = name;
  }
  return acc;
}, {});

export const getSpanishTeamName = (input) => {
  if (!input) return "";
  const canonical = resolveCanonicalTeam(input);
  return CANONICAL_TO_SPANISH[canonical] || input;
};

export const getFlagCodeForTeam = (input) => {
  const canonical = resolveCanonicalTeam(input);
  return FLAG_CODES[canonical] || "";
};
